mapper.select:
SELECT COUNT(1)
FROM tb_policy
WHERE INSURED_IDENTITY_CARD = #{insuredIdNo}
  AND PRODUCT_CODE = #{productCode}
  AND POLICY_STATUS IN ('SUBMIT', 'PENDING', 'RETURN')

      AND POLICY_NO != #{applicationId}

mapper.update:
UPDATE tb_policy
SET POLICY_STATUS = #{entity.policyStatus},
    UPDATE_TIME   = CURRENT_TIMESTAMP,
    UPDATE_USER   = #{entity.updateUser}

    , EFFECT_DATE = #{entity.effectDate}


    , EXPIRE_DATE = #{entity.expireDate}

WHERE POLICY_NO = #{entity.policyNo}
  AND POLICY_STATUS = #{previousStatus}

mapper.select:
SELECT COUNT(1)
FROM tb_policy pa
         LEFT JOIN tb_cust_user cu ON pa.MEMBER_ID = cu.MEMBER_ID


        AND pa.POLICY_NO = #{applicationId}


        AND cu.IDENTITY_CARD = #{applicantIdNo}


        AND pa.INSURED_IDENTITY_CARD = #{insuredIdNo}


        AND pa.POLICY_STATUS = #{applicationStatus}


        AND pa.PRODUCT_CODE = #{productCode}


        AND pa.APPLY_TIME  >=  #{submissionStartTime}


        AND pa.APPLY_TIME  <=  #{submissionEndTime}

SELECT pa.POLICY_NO AS applicationId, cu.IDENTITY_CARD AS applicantIdNo, COALESCE( cu.NAME, CASE WHEN cu.IDENTITY_CARD = pa.INSURED_IDENTITY_CARD THEN pa.INSURED_NAME ELSE NULL END ) AS applicantName, cu.GENDER AS applicantGender, cu.BIRTHDAY AS applicantBirthdate, pa.INSURED_IDENTITY_CARD AS insuredIdNo, pa.INSURED_NAME AS insuredName, pa.INSURED_GENDER AS insuredGender, pa.INSURED_BIRTHDAY AS insuredBirthdate, pa.POLICY_MOBILE AS contactPhone, pa.PRODUCT_CODE AS productCode, p.PRODUCT_NAME AS productName, pa.POLICY_STATUS AS applicationStatus, NULL AS relationshipToInsured, pa.INSURED_AMOUNT AS sumInsured, pa.PREMIUM_AMOUNT AS annualPremium, pa.RISK_LEVEL AS riskLevel, pa.APPLY_TIME AS submissionTime, pa.UPDATE_TIME AS reviewTime, pa.UPDATE_USER AS reviewedBy, NULL AS rejectionReason, pa.UPDATE_USER AS createdBy FROM tb_policy pa LEFT JOIN tb_product p ON pa.PRODUCT_CODE = p.PRODUCT_CODE LEFT JOIN tb_cust_user cu ON pa.MEMBER_ID = cu.MEMBER_ID
AND pa.POLICY_NO = #{applicationId}
AND cu.IDENTITY_CARD = #{applicantIdNo}
AND pa.INSURED_IDENTITY_CARD = #{insuredIdNo}
AND pa.POLICY_STATUS = #{applicationStatus}
AND pa.PRODUCT_CODE = #{productCode}
AND pa.APPLY_TIME >= #{submissionStartTime}
AND pa.APPLY_TIME <= #{submissionEndTime}
ORDER BY pa.APPLY_TIME
ASC DESC
LIMIT #{offset}, #{pageSize}

SELECT pa.POLICY_NO AS applicationId, cu.IDENTITY_CARD AS applicantIdNo, cu.NAME AS applicantName, cu.GENDER AS applicantGender, cu.BIRTHDAY AS applicantBirthdate, pa.INSURED_IDENTITY_CARD AS insuredIdNo, pa.INSURED_NAME AS insuredName, pa.INSURED_GENDER AS insuredGender, pa.INSURED_BIRTHDAY AS insuredBirthdate, NULL AS contactPhone, pa.PRODUCT_CODE AS productCode, p.PRODUCT_NAME AS productName, pa.POLICY_STATUS AS applicationStatus, NULL AS relationshipToInsured, pa.INSURED_AMOUNT AS sumInsured, pa.PREMIUM_AMOUNT AS annualPremium, pa.RISK_LEVEL AS riskLevel, pa.APPLY_TIME AS submissionTime, pa.UPDATE_TIME AS reviewTime, pa.UPDATE_USER AS reviewedBy, NULL AS rejectionReason, pa.UPDATE_USER AS createdBy FROM tb_policy pa LEFT JOIN tb_product p ON pa.PRODUCT_CODE = p.PRODUCT_CODE LEFT JOIN tb_cust_user cu ON pa.MEMBER_ID = cu.MEMBER_ID WHERE pa.POLICY_STATUS IN
#{status}
ORDER BY pa.APPLY_TIME DESC
